from pyfzf import FzfPrompt

class SFzfPrompt(FzfPrompt):
	def prompt(self, choices=[],multi=False,prompt_text=None,return_idx=False):
		${0:fzf_options} = ""
		if multi:
			${0:fzf_options} += "--multi "
		if not prompt_text is None:
			${0:fzf_options} += f'--prompt "{prompt_text}"'
		if return_idx:
			return self.prompt_index(choices,${0:fzf_options})
		else:
			return super().prompt(choices, ${0:fzf_options})

	def prompt_index(self,choices,${0:fzf_options}=""):
		choices_str = [str(x) for x in choices]
		selection =  self.prompt(choices_str,${0:fzf_options})
		indices = []
		for x in selection:
			indices.append(choices_str.index(x))
		return indices

from media_manager.core import MediaManager
def get_result_options(mm:MediaManager):
	result_options = set()
	for video_info in mm._video_infos:
		result_dirpath_parts = len(video_info.result_dirpath.parts)
		results = video_info.result_dirpath.glob("**/*.csv")
		for x in results:
			result_item = "/".join(x.parts[result_dirpath_parts:])
			result_options.add(result_item)

	result_options = list(result_options)

